import React from 'react'
import { useTranslation } from 'react-i18next'
import { Theme } from '@fs/zion-ui'
import ProfileSearch from '@fs/zion-profile-search'
import { baseUrl } from '@fs/zion-config'
import useChatSearchChats, { MAX_STREAM_SEARCH_LENGTH } from '../hooks/useChatSearchChats'
import { useChatState } from '../providers/ChatStateProvider'
import isTouchScreen from '../helpers/isTouchScreen'

export default function ChatWindowHeaderSearch({ isOnCreateNewChat }) {
  const [t] = useTranslation()
  const { exclusionList, inclusions, onInputTextChange, onSuggestionSelected, onClear, focusRef } = useChatSearchChats({
    disableAutoFocus: isOnCreateNewChat || isTouchScreen,
  })
  const { darkMode } = useChatState()
  return (
    <Theme theme={darkMode ? 'night' : 'day'} transparent>
      <ProfileSearch
        clearInputOnSelection
        clearable
        data-testid="chat-header-search"
        exclusionList={exclusionList}
        hideMessaging
        inclusions={inclusions}
        onClear={onClear}
        onInputTextChange={onInputTextChange}
        onSuggestionSelected={onSuggestionSelected}
        placeholder={t('chat.search-for-people.placeholder', 'Search for people and chats')}
        promptOptIn={false}
        optInUrl={`${baseUrl || window.location.origin}/help/helper/profile-opt-in`}
        ref={focusRef}
        maxLength={MAX_STREAM_SEARCH_LENGTH}
        shouldUseUserConnections
      />
    </Theme>
  )
}
